    active_block = None
    for block in blocks:
        if 'status: "active"' in block or 'status: active' in block:
            active_block = block
            break

    if not active_block:
        active_block = blocks[-1]

    # Clean the chosen block
    cleaned_lines = []
    lines = active_block.split('\n')
    for line in lines:
        if line.strip() == '#!#!#!':
            cleaned_lines.append(line.strip())
        else:
            # Remove leading '#' or '# '
            cleaned_line = re.sub(r'^#\s?', '', line)
            cleaned_lines.append(cleaned_line)

    cleaned_block_str = '\n'.join(cleaned_lines)

    # Remove all blocks from content
    # Also remove the comments wrapping them if it's C
    if file_path.endswith('.c'):
        # Matches /* ... #!#!#! ... #!#!#! ... */
        new_content = re.sub(r'/\*\s*#!#!#!.*?#!#!#! \*/', '', content, flags=re.DOTALL)
        new_content = re.sub(r'/\*\s*#!#!#!.*?#!#!#! \*/', '', new_content, flags=re.DOTALL) # double check for different spacing
