        for block in blocks:
            # Try to find the block and its surrounding comment
            pattern = r'/\*.*?' + re.escape(block) + r'.*?\*/'
            new_content = re.sub(pattern, '', new_content, flags=re.DOTALL)
    else:
        new_content = content
        for block in blocks:
            new_content = new_content.replace(block, '')

    # Specific cleanup: remove duplicate imports/includes that often surround blocks
    lines = new_content.split('\n')
    seen_includes = set()
    final_lines = []

    # We'll only deduplicate lines that start with import/from (Python) or #include (C)
    # and only if they appear before any real code starts (to be safe)
    code_started = False
    for line in lines:
        trimmed = line.strip()
        if not trimmed:
            final_lines.append(line)
            continue

        is_import = False
        if file_path.endswith('.py'):
            if trimmed.startswith('import ') or trimmed.startswith('from '):
                is_import = True
        elif file_path.endswith('.c'):
            if trimmed.startswith('#include '):
                is_import = True

        if is_import and not code_started:
            if trimmed not in seen_includes:
                seen_includes.add(trimmed)
                final_lines.append(line)
        else:
            if trimmed and not (trimmed.startswith('import ') or trimmed.startswith('from ') or trimmed.startswith('#include ')):
                # If we hit something else, consider code started for deduplication purposes
                # but we still want to keep imports that might be later (though unusual)
                if not (trimmed.startswith('/*') or trimmed.startswith('//') or trimmed.startswith('"""') or trimmed.startswith("'''") or trimmed.startswith('#')):
                    code_started = True
            final_lines.append(line)

    new_content = '\n'.join(final_lines)

    # Remove redundant empty lines at the top
    new_content = new_content.lstrip()

    # Reposition
    if file_path.endswith('.py'):
        if new_content.startswith('#!'):
            shebang_end = new_content.find('\n') + 1
            final_output = new_content[:shebang_end] + '\n' + cleaned_block_str + '\n\n' + new_content[shebang_end:]
        else:
            final_output = cleaned_block_str + '\n\n' + new_content
    elif file_path.endswith('.c'):
        final_output = "/*\n" + cleaned_block_str + "\n*/\n\n" + new_content
    else:
        final_output = cleaned_block_str + '\n\n' + new_content

    # Final cleanup of multiple newlines
    final_output = re.sub(r'\n{3,}', '\n\n', final_output)

    with open(file_path, 'w') as f:
        f.write(final_output)
    print(f"Fixed: {file_path}")

def main():
    directory = 'exploits'
    for root, dirs, files in os.walk(directory):
        for file in files:
            if file.endswith(('.py', '.c')) and not file.startswith('.'):
                file_path = os.path.join(root, file)
                fix_metadata(file_path)

